  afterEach(() => {
    vi.useRealTimers();
  });

  test('rejects', async () => {
    const result = foo();

    await vi.advanceTimersByTimeAsync(100);

    await expect(result).rejects.toThrow(); // Succeeds, but the error seems to end up being "unhandled" by vitest.
  });
});
```

